import React from 'react';

function Trade(props) {
    return(
        <div>
            {props.trade.id}
            <buffer></buffer>
            {props.trade.stock}
            <buffer></buffer>
            {props.trade.method}
            <buffer></buffer>
            {props.trade.quantity}
            <buffer></buffer>
            {props.trade.profitLoss}
            <buffer></buffer>
        </div>
    )
}

export default Trade;
